const input = $input.first().json;
const telefono = input.telefono;
const data = input.data || {};

const camposPermitidos = [
  'nombre', 'email', 'origen', 'domicilio',
  'modelos_interes', 'grupo_familiar',
  'credito_bancario', 'presupuesto', 'etapa_actual'
];

//const updates = {};
//for (const campo of camposPermitidos) {
//  if (data[campo] !== undefined && data[campo] !== null && data[campo] !== '') {
//    updates[campo] = data[campo];
//  }
//}

const updates = {};
for (const campo of camposPermitidos) {
  const valor = data[campo];
  if (valor === undefined || valor === null || valor === '') continue;

  // Manejo especial para modelos_interes
  if (campo === 'modelos_interes') {
    // Normalizar string a array si el LLM mandó mal
    const arr = Array.isArray(valor) ? valor : [valor];
    // Solo guardar si tiene elementos
    if (arr.length > 0) updates[campo] = arr;
    continue;
  }

  updates[campo] = valor;
}



updates['updated_at'] = new Date().toISOString();

return [{
  json: {
    telefono,
    ...updates
  }
}];

const record = $input.first().json;

return [{
  json: {
    success: true,
    message: `Perfil actualizado correctamente`,
    telefono: record.telefono,
    campos_actualizados: Object.keys(record).filter(k => 
      !['id', 'telefono', 'created_at'].includes(k)
    ),
    updated_at: record.updated_at
  }
}];

const error = $input.first().json;

return [{
  json: {
    success: false,
    message: `Error al actualizar perfil`,
    telefono: $('filtra-datos').first().json.telefono,
    error_details: error.message || error.error || JSON.stringify(error),
    timestamp: new Date().toISOString()
  }
}];
